mapper.select:
/* com.shop.mapper.product.productMng.selectProdInfoList */ SELECT TP.ID AS id , TP.PARTNER_ID AS partnerId , TP.PROD_CD AS prodCd , TP.PROD_NM AS prodNm , TP.PROD_TP AS prodTp , TP.PROD_DET_TP AS prodDetTp , TP.COMPOSITION AS composition , TP.REP_FILE_ID AS repFileId , TP.DETAIL_FILE_ID AS detailFileId , TP.SIZE_FILE_ID AS sizeFileId , TP.ETC_FILE_ID AS etcFileId , TP.MAKE_YMD AS makeYmd , TP.ORG_AMT AS orgAmt , TP.SELL_AMT AS sellAmt , TP.DISCOUNT_RATE AS discountRate , FN_GET_CODE('90010', TP.PROD_TP) prodTpNm , FN_GET_CODE('90011', TP.PROD_DET_TP) prodDetTpNm , STRING_AGG(TPD.PRODUCT_DET_COLOR, ',') AS prodColors , STRING_AGG(DISTINCT TPD.PRODUCT_DET_SIZE, ',') AS prodSizes , COUNT(TPD) AS prodDetCnt , (SELECT COUNT(1) FROM TB_FILE_DET FDI WHERE FDI.FILE_ID = TP.REP_FILE_ID AND FDI.DEL_YN = 'N') AS repFileIdCnt , (SELECT COUNT(1) FROM TB_FILE_DET FDI WHERE FDI.FILE_ID = TP.DETAIL_FILE_ID AND FDI.DEL_YN = 'N') AS detailFileIdCnt , (SELECT COUNT(1) FROM TB_FILE_DET FDI WHERE FDI.FILE_ID = TP.SIZE_FILE_ID AND FDI.DEL_YN = 'N') AS sizeFileIdCnt , (SELECT COUNT(1) FROM TB_FILE_DET FDI WHERE FDI.FILE_ID = TP.ETC_FILE_ID AND FDI.DEL_YN = 'N') AS etcFileIdCnt , TP.IS_SPRING , TP.IS_SUMMER , TP.IS_AUTUMN , TP.IS_WINTER FROM TB_PRODUCT TP LEFT JOIN TB_PRODUCT_DET TPD ON TP.ID = TPD.PRODUCT_ID AND TPD.DEL_YN = 'N'
AND TP.DEL_YN = 'N'
AND TP.PROD_NM LIKE CONCAT('%' ,#{prodNm} ,'%')
GROUP BY TP.ID ORDER BY TP.ID;

/* com.shop.mapper.product.productMng.selectProdDetInfo */ SELECT TPD.ID AS id , TPD.PRODUCT_ID AS productId , TPD.PRODUCT_DET_SEQ AS productDetSeq , TPD.PRODUCT_DET_SIZE AS productDetSize , TPD.PRODUCT_DET_COLOR AS productDetColor , TPD.SKU_DISCOUNT_RATE AS skuDiscountRate , TPD.FILE_ID AS fileId , TPD.SLEEP_YN AS sleepYn , TPD.PRODUCT_DET_CNTN AS productDetCntn FROM TB_PRODUCT_DET TPD
AND TPD.DEL_YN = 'N'
AND TPD.PRODUCT_ID = #{prodId}
AND TPD.PRODUCT_DET_COLOR = #{prodDetColor}
ORDER BY TPD.ID

/* com.shop.mapper.product.productMng.selectCategoryProductInfoList */ SELECT TP.ID AS id , TP.PARTNER_ID AS partnerId , TP.PROD_CD AS prodCd , TP.PROD_NM AS prodNm , TP.PROD_TP AS prodTp , TP.PROD_DET_TP AS prodDetTp , TP.COMPOSITION AS composition , TP.REP_FILE_ID AS repFileId , TP.DETAIL_FILE_ID AS detailFileId , TP.SIZE_FILE_ID AS sizeFileId , TP.ETC_FILE_ID AS etcFileId , TP.MAKE_YMD AS makeYmd , TP.ORG_AMT AS orgAmt , TP.SELL_AMT AS sellAmt , TP.DISCOUNT_RATE AS discountRate , FN_GET_CODE('90010', TP.PROD_TP) prodTpNm , FN_GET_CODE('90011', TP.PROD_DET_TP) prodDetTpNm , TP.IS_SPRING , TP.IS_SUMMER , TP.IS_AUTUMN , TP.IS_WINTER , STRING_AGG(TPD.PRODUCT_DET_COLOR, ',') AS prodColors , STRING_AGG(DISTINCT TPD.PRODUCT_DET_SIZE, ',') AS prodSizes
, CPD.ID AS categoryProductId , CPD.SEQ AS seq , CPD.CATEGORY_ID AS categoryId FROM TB_PRODUCT TP JOIN TB_CATEGORY_PRODUCT CPD ON TP.ID = CPD.PRODUCT_ID AND CPD.DEL_YN = 'N' LEFT JOIN TB_PRODUCT_DET TPD ON TP.ID = TPD.PRODUCT_ID AND TPD.DEL_YN = 'N'
AND TP.DEL_YN = 'N'
AND CPD.CATEGORY_ID = #{categoryId}
GROUP BY TP.ID, CPD.ID ORDER BY TP.ID;

mapper.insert:
/* com.shop.mapper.product.productMng.insertProduct */
INSERT INTO TB_PRODUCT (
      PARTNER_ID
    , PROD_CD
    , PROD_NM
    , PROD_TP
    , PROD_DET_TP
    , COMPOSITION

    , REP_FILE_ID


    , DETAIL_FILE_ID


    , SIZE_FILE_ID


    , ETC_FILE_ID

    , MAKE_YMD

    , ORG_AMT


    , SELL_AMT


    , DISCOUNT_RATE

    , CRE_USER
    , UPD_USER

    , IS_SPRING


    , IS_SUMMER


    , IS_AUTUMN


    , IS_WINTER

) VALUES (
      #{partnerId}
    , FN_GET_NEXT_PRODUCT_CODE(#{partnerId})
    , #{prodNm}
    , #{prodTp}
    , #{prodDetTp}
    , #{composition}

    , #{repFileId}


    , #{detailFileId}


    , #{sizeFileId}


    , #{etcFileId}

    , #{makeYmd}

    , #{orgAmt}


    , #{sellAmt}


    , #{discountRate}

    , #{creUser}
    , #{updUser}

    , #{isSpring}


    , #{isSummer}


    , #{isAutumn}


    , #{isWinter}

)

/* com.shop.mapper.product.productMng.insertProductDet */
INSERT INTO TB_PRODUCT_DET (
      PRODUCT_ID
    , PRODUCT_DET_SEQ
    , PRODUCT_DET_SIZE
    , PRODUCT_DET_COLOR
    , SKU_DISCOUNT_RATE

    , FILE_ID


    , PRODUCT_DET_CNTN

    , SLEEP_YN
    , CRE_USER
    , UPD_USER
) VALUES (
      #{productId}
    , GET_NEXT_PRODUCT_DET_SEQ(#{productId})
    , #{productDetSize}
    , #{productDetColor}
    , #{skuDiscountRate}

    , #{fileId}


    , #{productDetCntn}

    , #{sleepYn}
    , #{creUser}
    , #{updUser}
)

mapper.update:
/* com.shop.mapper.product.productMng.updateProduct */
UPDATE TB_PRODUCT SET
      UPD_TM   = NOW()
    , UPD_USER = #{updUser}

    , PROD_NM = #{prodNm}


    , PROD_TP = #{prodTp}


    , PROD_DET_TP = #{prodDetTp}


    , COMPOSITION = #{composition}


    , MAKE_YMD = #{makeYmd}


    , ORG_AMT = #{orgAmt}


    , SELL_AMT = #{sellAmt}


    , DISCOUNT_RATE = #{discountRate}

    , IS_SPRING = #{isSpring}
    , IS_SUMMER = #{isSummer}
    , IS_AUTUMN = #{isAutumn}
    , IS_WINTER = #{isWinter}
WHERE ID = #{id}

/* com.shop.mapper.product.productMng.updateProductDet */
UPDATE TB_PRODUCT_DET SET
      UPD_TM   = NOW()
    , UPD_USER = #{updUser}

    , PRODUCT_ID = #{productId}


    , PRODUCT_DET_SEQ = #{productDetSeq}


    , PRODUCT_DET_SIZE = #{productDetSize}


    , PRODUCT_DET_COLOR = #{productDetColor}


    , SKU_DISCOUNT_RATE = #{skuDiscountRate}


    , FILE_ID = #{fileId}


    , SLEEP_YN = #{sleepYn}


    , PRODUCT_DET_CNTN = #{productDetCntn}

WHERE ID = #{id}

/* com.shop.mapper.product.productMng.deleteProduct */
UPDATE TB_PRODUCT SET
      UPD_TM   = NOW()
    , UPD_USER = #{updUser}
    , DEL_YN = 'Y'
WHERE ID = #{id}

/* com.shop.mapper.product.productMng.deleteProductDet */
UPDATE TB_PRODUCT_DET SET
      UPD_TM   = NOW()
    , UPD_USER = #{updUser}
    , DEL_YN = 'Y'
WHERE ID = #{id}

mapper.select:
/* com.shop.mapper.product.productMng.selectProdInfoListWithExclusion */ SELECT TP.ID AS id , TP.PARTNER_ID AS partnerId , TP.PROD_CD AS prodCd , TP.PROD_NM AS prodNm , FN_GET_CODE('90010', TP.PROD_TP) prodTpNm , FN_GET_CODE('90011', TP.PROD_DET_TP) prodDetTpNm , STRING_AGG(TPD.PRODUCT_DET_COLOR, ',') AS prodColors , STRING_AGG(DISTINCT TPD.PRODUCT_DET_SIZE, ',') AS prodSizes FROM TB_PRODUCT TP LEFT JOIN TB_PRODUCT_DET TPD ON TP.ID = TPD.PRODUCT_ID AND TPD.DEL_YN = 'N'
AND TP.DEL_YN = 'N'
AND TP.PROD_NM LIKE CONCAT('%' ,#{prodNm} ,'%')
AND NOT EXISTS ( SELECT 1 FROM TB_CATEGORY_PRODUCT CPD
AND CPD.PRODUCT_ID = TP.ID
AND CPD.CATEGORY_ID = #{categoryId}
)
GROUP BY TP.ID ORDER BY TP.ID;

mapper.update:
/* com.shop.mapper.product.productMng.updateCategoryProduct */ UPDATE TB_CATEGORY_PRODUCT SET
SEQ = #{seq},
CATEGORY_ID = #{categoryId},
PRODUCT_ID = #{productId},
UPD_USER = #{updUser}, UPD_TM = NOW() WHERE ID = #{id}

/* com.shop.mapper.product.productMng.deleteCategoryProduct */
UPDATE TB_CATEGORY_PRODUCT SET
      UPD_TM = NOW()
    , UPD_USER = #{updUser}
    , DEL_YN = 'Y'
WHERE ID = #{id}
